import * as React from 'react';
import {
  ImageCropper,
  centerCrop,
  makeAspectCrop,
  cropToFile,
} from '@tale-ui/react/image-cropper';
import type { Crop, PixelCrop } from '@tale-ui/react/image-cropper';
import { Card } from '@tale-ui/react/card';
import { Column } from '@tale-ui/react/column';
import { Row } from '@tale-ui/react/row';
import { Button } from '@tale-ui/react/button';
import { Text } from '@tale-ui/react/text';
import { FileTrigger } from '@tale-ui/react/file-trigger';
import { Avatar } from '@tale-ui/react/avatar';

function centerAspectCrop(mediaWidth: number, mediaHeight: number, aspect: number) {
  return centerCrop(
    makeAspectCrop({ unit: '%', width: 80 }, aspect, mediaWidth, mediaHeight),
    mediaWidth,
    mediaHeight,
  );
}

export function AvatarPhotoCropper() {
  const [imgSrc, setImgSrc] = React.useState<string>('');
  const [crop, setCrop] = React.useState<Crop>();
  const [completedCrop, setCompletedCrop] = React.useState<PixelCrop>();
  const [savedPreview, setSavedPreview] = React.useState<string | null>(null);

  function onSelectFile(fileList: FileList | null) {
    if (!fileList || fileList.length === 0) return;
    const reader = new FileReader();
    reader.addEventListener('load', () => {
      setImgSrc(reader.result?.toString() ?? '');
      setCrop(undefined);
      setSavedPreview(null);
    });
    reader.readAsDataURL(fileList[0]);
  }

  function onImageLoad(e: React.SyntheticEvent<HTMLImageElement>) {
    const { naturalWidth: width, naturalHeight: height } = e.currentTarget;
    setCrop(centerAspectCrop(width, height, 1));
  }

  async function handleSave() {
    if (!completedCrop || !imgSrc) return;
    const file = await cropToFile(imgSrc, completedCrop);
    if (file) {
      setSavedPreview(URL.createObjectURL(file));
    }
  }

  return (
    <Card.Root style={{ maxWidth: 480 }}>
      <Card.Header>
        <Column gap="xs">
          <Text variant="heading">Crop Avatar Photo</Text>
          <Text color="muted">Select a photo, then drag to adjust the crop area.</Text>
        </Column>
      </Card.Header>

      <Card.Body>
        <Column gap="m">
          {imgSrc ? (
            <ImageCropper.Root
              crop={crop}
              onChange={setCrop}
              onComplete={setCompletedCrop}
              aspect={1}
              circularCrop
            >
              <ImageCropper.Img
                src={imgSrc}
                alt="Crop your avatar"
                onLoad={onImageLoad}
                style={{ maxHeight: 360, width: '100%' }}
              />
            </ImageCropper.Root>
          ) : (
            <div
              style={{
                padding: 'var(--space-2xl)',
                border: '2px dashed var(--neutral-20)',
                borderRadius: 'var(--radius-m)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Text color="muted">No photo selected. Choose one below.</Text>
            </div>
          )}

          {savedPreview && (
            <Row gap="s" style={{ alignItems: 'center' }}>
              <Text variant="label">Preview</Text>
              <Avatar.Root size="xl">
                <Avatar.Image src={savedPreview} alt="Cropped avatar preview" />
                <Avatar.Fallback>?</Avatar.Fallback>
              </Avatar.Root>
            </Row>
          )}
        </Column>
      </Card.Body>

      <Card.Footer>
        <Row gap="s">
          <FileTrigger onSelect={onSelectFile}>
            <Button variant="neutral">Change photo</Button>
          </FileTrigger>
          <Button
            variant="primary"
            isDisabled={!imgSrc || !completedCrop}
            onPress={handleSave}
          >
            Save avatar
          </Button>
        </Row>
      </Card.Footer>
    </Card.Root>
  );
}
